    public Common findEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
    {
        Common ret = next findEntityDataSource(_entityCtx, _dataSourceCtx);
    
        if (ret)
        {
            return ret;
        }

        switch (_dataSourceCtx.name())
        {
            case dataEntityDataSourceStr(NumberSequencesReferenceV2Entity, NumberSequenceTableV2Entity) :
                NumberSequenceTableV2Entity NumberSequenceTableV2Entity = null;
                
                select forUpdate firstOnly NumberSequenceTableV2Entity
                    where (NumberSequenceTableV2Entity.ScopeType == this.ScopeType && NumberSequenceTableV2Entity.ScopeValue == '' &&
                    NumberSequenceTableV2Entity.NumberSequenceCode == this.NumberSequenceCode);

                ret = NumberSequenceTableV2Entity;

                break;

            default :
                return ret;
        }
    
        return ret;
    }
